def route(record: dict) -> str:
    required = {'case_id', 'query', 'docs', 'metric', 'version', 'expected_top'}
    absent = sorted(k for k in required if k not in record)
    if absent:
        return "MISSING:" + ",".join(absent)
    ok = not (min(record["docs"], key=lambda k: sum(a*b for a,b in zip(record["query"],record["docs"][k]))) == record["expected_top"])
    return "PASS" if ok else "REJECT_EMBEDDING_RANK"

valid = {'case_id': 'CASO-PUN-048-1A', 'query': [1.0, 0.0], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1'}
invalid = {'case_id': 'CASO-PUN-048-1A', 'query': [], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1'}
incomplete = dict(valid)
if "expected_top" in incomplete:
    del incomplete["expected_top"]
print(route(valid), route(invalid), route(incomplete))

